return items.map(item => ({
  json: {
    action: item.json.body.action,
    ...item.json.body.data,
    pin: item.json.body.pin
  }
}));

// Stock Existente? - Verifica si el producto de la compra ya existe en el catálogo

const catalogo = $('Filter1').all();
const compras  = $('Normalizacion Webhook Compras').all();

const norm = (v) => String(v ?? '').trim().toUpperCase();

// Set de códigos existentes en el catálogo
const codigosCatalogo = new Set(
  catalogo
    .map(i => norm(i.json['Código'] ?? i.json.codigo))
    .filter(Boolean)
);

// Para cada item de la compra, marcar si existe
return compras.map(item => {
  const codigo = norm(item.json.codigo);
  const existe = codigosCatalogo.has(codigo);

  return {
    json: {
      ...item.json,
      codigo_normalizado: codigo,
      existe,
      estado: existe ? 'EXISTE' : 'NO_EXISTE',
    },
  };
});

// ═══════════════════════════════════════════════════════════════════════════
// RESOLVER BOM DEL PEDIDO — v5 (con invariantes de input)
// ───────────────────────────────────────────────────────────────────────────
// Cambios v5 respecto a v4:
//   - Nuevo bloque de INVARIANTES al inicio que valida la integridad del
//     input (pedido + BOM + stock) antes de resolver.
//   - Si alguna violación es detectada → el resolver emite el output con
//     `violaciones: [...]` y el mapeo posterior lo bloquea.
//   - 10 invariantes identificados con IDs INV-R01..INV-R10.
//
// Filosofía:
//   Un invariante es una condición que SIEMPRE debe ser verdadera. Si se
//   viola, es un bug del sistema (planilla corrupta, normalizador roto,
//   upstream malo). No es responsabilidad del usuario final; es un error
//   de plataforma que debe alertar para ser investigado.
//
// Input (igual que v4):
//   - $('normalizar pedido').all()  → 1 header + N items
//   - $input.all()                   → BOM + Stock concatenado (Merge append)
// ═══════════════════════════════════════════════════════════════════════════

// ── Helpers ────────────────────────────────────────────────────────────────

const normText = (s) =>
  String(s ?? '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

const pick = (row, ...keys) => {
  for (const k of keys) {
    if (row[k] !== undefined && row[k] !== null && row[k] !== '') return row[k];
    const match = Object.keys(row).find((rk) => normText(rk) === normText(k));
    if (match && row[match] !== undefined && row[match] !== null && row[match] !== '') {
      return row[match];
    }
  }
  return null;
};

const parseMoney = (v) => {
  if (v === null || v === undefined || v === '') return 0;
  const cleaned = String(v).replace(/[^\d.,\-]/g, '').replace(/\./g, '').replace(',', '.');
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : 0;
};

const parseNumber = (v) => {
  if (v === null || v === undefined || v === '') return 0;
  const n = Number(String(v).trim().replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
};

// ── Productos considerados "placa estructural" ────────────────────────────
const PRODUCTOS_PLACA = new Set([
  'Placa MDF 18mm',
  'Placa MDF Crudo 18mm',
  'Placa Rauvisio',
]);

// ── Parser de material del BOM ────────────────────────────────────────────
const parsearMaterialBom = (materialStr) => {
  const str = String(materialStr || '').trim();
  if (!str) return null;
  const partes = str.split(/\s+-\s+/);
  if (partes.length < 2) {
    return { producto: str, categoria: null, placeholder: false, filtroExtra: null, raw: str };
  }
  const producto = partes[0].trim();
  const resto = partes.slice(1).join(' - ').trim();
  if (resto.startsWith('*')) {
    const matchNivel = resto.match(/\*\s*Nivel\s+\d+\s*(.*)$/i);
    const filtroExtra = matchNivel && matchNivel[1] ? matchNivel[1].trim() : null;
    return { producto, categoria: null, placeholder: true, filtroExtra: filtroExtra || null, raw: str };
  }
  return { producto, categoria: resto, placeholder: false, filtroExtra: null, raw: str };
};

// ═══════════════════════════════════════════════════════════════════════════
// 1. Separar pedido, BOM y stock
// ═══════════════════════════════════════════════════════════════════════════

const normalizados = $('normalizar pedido').all().map((i) => i.json);
const header = normalizados.find((r) => r.tipo === 'pedido');
const items = normalizados.filter((r) => r.tipo === 'item');

if (!header) throw new Error('[resolver_bom] No se encontró el header del pedido.');
if (items.length === 0) throw new Error('[resolver_bom] El pedido no tiene items.');

const rowsMerged = $input.all().map((i) => i.json);
const bomRows = rowsMerged.filter(
  (r) => r.tipo_mueble && r.material && r.nivel !== undefined && r.nivel !== null && r.nivel !== '',
);
const stockRows = rowsMerged.filter((r) => pick(r, 'Código', 'codigo'));

if (bomRows.length === 0) throw new Error('[resolver_bom] No llegaron filas de BOM.');
if (stockRows.length === 0) throw new Error('[resolver_bom] No llegaron filas de Stock.');

// ═══════════════════════════════════════════════════════════════════════════
// 2. Normalizar catálogo de stock
// ═══════════════════════════════════════════════════════════════════════════

const catalogoStock = stockRows
  .map((r) => ({
    codigo: String(pick(r, 'Código', 'codigo') || '').trim(),
    seccion: String(pick(r, 'Sección', 'Seccion', 'seccion') || '').trim(),
    producto: String(pick(r, 'Producto', 'producto') || '').trim(),
    categoria: String(pick(r, 'Categoría', 'Categoria', 'categoria') || '').trim(),
    color_variante: String(pick(r, 'Color / Variante', 'Color/Variante', 'color_variante') || '').trim(),
    marca: String(pick(r, 'Marca', 'marca') || '').trim(),
    medida: String(pick(r, 'Medida', 'medida') || '').trim(),
    stock: parseNumber(pick(r, 'Stock Actual', 'stock_actual', 'stock', 'STOCK')),
    precio_unit: parseMoney(pick(r, 'Precio Unit.', 'Precio Costo', 'precio_unit', 'precio')),
    row_number: r.row_number,
  }))
  .filter((x) => x.codigo && x.producto);

// ═══════════════════════════════════════════════════════════════════════════
// 3. CHEQUEO DE INVARIANTES DE INPUT (antes de resolver)
// ═══════════════════════════════════════════════════════════════════════════
// Un invariante violado = bug de plataforma. Se emite al output y el mapeo
// posterior bloquea el procesamiento.

const violaciones = [];

const addViolacion = (id, tipo, mensaje, datos = {}) => {
  violaciones.push({
    invariante_id: id,
    tipo,
    mensaje,
    datos,
    origen: 'resolver_bom',
  });
};

// INV-R01: Header con datos mínimos
if (!header.pedido_id || !header.cliente_nombre) {
  addViolacion('INV-R01', 'header_incompleto',
    'El pedido no tiene pedido_id o cliente_nombre.',
    { pedido_id: header.pedido_id || null, cliente_nombre: header.cliente_nombre || null });
}

// INV-R02: Cada item tiene campos mínimos
for (const item of items) {
  const faltantes = [];
  if (!item.item_id) faltantes.push('item_id');
  if (!item.tipo_mueble) faltantes.push('tipo_mueble');
  if (item.categoria === undefined || item.categoria === null || item.categoria === '') faltantes.push('categoria (nivel)');
  if (!item.color) faltantes.push('color');
  if (faltantes.length > 0) {
    addViolacion('INV-R02', 'item_incompleto_datos',
      `Item ${item.item_id || '(sin id)'} tiene campos faltantes: ${faltantes.join(', ')}.`,
      { item_id: item.item_id || null, faltantes });
  }
}

// INV-R03: Nivel numérico entre 1 y 5
for (const item of items) {
  const n = parseNumber(item.categoria);
  if (!Number.isFinite(n) || n < 1 || n > 5 || n !== Math.floor(n)) {
    addViolacion('INV-R03', 'nivel_invalido',
      `Item ${item.item_id} tiene nivel inválido: "${item.categoria}". Esperado: entero entre 1 y 5.`,
      { item_id: item.item_id, nivel_recibido: item.categoria });
  }
}

// INV-R04: Cada (tipo_mueble, nivel) del pedido existe en el BOM
for (const item of items) {
  const nivelItem = parseNumber(item.categoria);
  const tipoMuebleItem = String(item.tipo_mueble || '').trim();
  if (!tipoMuebleItem || !Number.isFinite(nivelItem)) continue; // ya se reportó en R02/R03
  const existe = bomRows.some(
    (r) => String(r.tipo_mueble || '').trim() === tipoMuebleItem && parseNumber(r.nivel) === nivelItem,
  );
  if (!existe) {
    addViolacion('INV-R04', 'bom_inexistente',
      `No existe BOM para "${tipoMuebleItem}" nivel ${nivelItem}.`,
      { item_id: item.item_id, tipo_mueble: tipoMuebleItem, nivel: nivelItem });
  }
}

// INV-R05: Todo material del BOM parsea correctamente
for (const b of bomRows) {
  const parsed = parsearMaterialBom(b.material);
  if (!parsed || !parsed.producto) {
    addViolacion('INV-R05', 'material_malformado',
      `Material mal escrito en Estándares: "${b.material}". Formato: "Producto - Categoría" o "Producto - * Nivel X".`,
      { tipo_mueble: b.tipo_mueble, nivel: b.nivel, material: b.material });
  }
}

// INV-R06: Todo Producto del BOM existe en el catálogo de stock
const productosStock = new Set(catalogoStock.map((c) => normText(c.producto)));
const productosBomChequeados = new Set();
for (const b of bomRows) {
  const parsed = parsearMaterialBom(b.material);
  if (!parsed || !parsed.producto) continue;
  const prodNorm = normText(parsed.producto);
  if (productosBomChequeados.has(prodNorm)) continue;
  productosBomChequeados.add(prodNorm);
  if (!productosStock.has(prodNorm)) {
    addViolacion('INV-R06', 'producto_sin_stock',
      `Producto "${parsed.producto}" del BOM no existe en el catálogo de stock.`,
      { producto: parsed.producto, material: b.material });
  }
}

// INV-R07: Stock y precios del catálogo son ≥ 0
for (const c of catalogoStock) {
  if (c.stock < 0) {
    addViolacion('INV-R07', 'stock_negativo_en_catalogo',
      `Código ${c.codigo} tiene stock negativo: ${c.stock}.`,
      { codigo: c.codigo, stock: c.stock });
  }
  if (c.precio_unit < 0) {
    addViolacion('INV-R07', 'precio_negativo_en_catalogo',
      `Código ${c.codigo} tiene precio negativo: ${c.precio_unit}.`,
      { codigo: c.codigo, precio: c.precio_unit });
  }
}

// INV-R08: No hay códigos duplicados en el catálogo
const contadorCodigos = new Map();
for (const c of catalogoStock) {
  contadorCodigos.set(c.codigo, (contadorCodigos.get(c.codigo) || 0) + 1);
}
for (const [codigo, count] of contadorCodigos) {
  if (count > 1) {
    addViolacion('INV-R08', 'codigo_duplicado',
      `El código "${codigo}" aparece ${count} veces en el catálogo.`,
      { codigo, ocurrencias: count });
  }
}

// INV-R09: Cantidad del BOM es > 0
for (const b of bomRows) {
  const cant = parseMoney(b.cantidad);
  if (cant <= 0) {
    addViolacion('INV-R09', 'cantidad_bom_invalida',
      `Material "${b.material}" (${b.tipo_mueble} N${b.nivel}) tiene cantidad inválida: ${b.cantidad}.`,
      { tipo_mueble: b.tipo_mueble, nivel: b.nivel, material: b.material, cantidad: b.cantidad });
  }
}

// INV-R10: Al menos 1 item en el pedido (ya chequeado arriba con throw, pero lo dejo explícito)
if (items.length === 0) {
  addViolacion('INV-R10', 'pedido_sin_items',
    'El pedido no tiene items.',
    { pedido_id: header.pedido_id });
}

// ═══════════════════════════════════════════════════════════════════════════
// 4. Resolver BOM por item (solo si no hay violaciones críticas de input)
// ═══════════════════════════════════════════════════════════════════════════
// Si hay violaciones, igual resolvemos lo que se pueda para tener trazabilidad,
// pero el mapeo posterior bloqueará el procesamiento.

const consumoPorCodigo = new Map();
const itemsResueltos = [];
const erroresItems = [];
const itemsIncompletos = [];

const addConsumo = (elegido, materialRaw, producto, categoria, unidadBom, cantidad, itemId, colorSolicitado) => {
  if (!consumoPorCodigo.has(elegido.codigo)) {
    consumoPorCodigo.set(elegido.codigo, {
      codigo: elegido.codigo,
      material_bom: materialRaw,
      producto: elegido.producto,
      categoria_stock: elegido.categoria,
      color_variante: elegido.color_variante,
      medida: elegido.medida,
      marca: elegido.marca,
      unidad_bom: unidadBom,
      precio_unit: elegido.precio_unit,
      stock_actual: elegido.stock,
      row_number: elegido.row_number,
      requerido: 0,
      items_asociados: [],
      color_solicitado: colorSolicitado,
    });
  }
  const cons = consumoPorCodigo.get(elegido.codigo);
  cons.requerido += cantidad;
  if (!cons.items_asociados.includes(itemId)) cons.items_asociados.push(itemId);
};

const elegirPorColor = (candidatos, colorNormItem) => {
  if (!colorNormItem) return null;
  let match = candidatos.find((c) => normText(c.color_variante) === colorNormItem);
  if (match) return match;
  match = candidatos.find((c) => normText(c.color_variante).includes(colorNormItem));
  if (match) return match;
  match = candidatos.find((c) => colorNormItem.includes(normText(c.color_variante)) && c.color_variante);
  if (match) return match;
  match = candidatos.find((c) => normText(c.categoria) === colorNormItem);
  if (match) return match;
  match = candidatos.find((c) =>
    normText(`${c.categoria} ${c.color_variante}`).includes(colorNormItem),
  );
  if (match) return match;
  match = candidatos.find(
    (c) =>
      normText(c.color_variante).includes('color a eleccion') ||
      normText(c.categoria).includes('color a eleccion'),
  );
  return match || null;
};

for (const item of items) {
  const nivelItem = parseNumber(item.categoria);
  const tipoMuebleItem = String(item.tipo_mueble || '').trim();
  const colorItem = String(item.color || '').trim();
  const colorNormItem = normText(colorItem);

  const bomItem = bomRows.filter(
    (r) =>
      String(r.tipo_mueble || '').trim() === tipoMuebleItem &&
      parseNumber(r.nivel) === nivelItem,
  );

  if (bomItem.length === 0) {
    erroresItems.push({
      item_id: item.item_id,
      tipo: 'sin_bom',
      tipo_mueble: tipoMuebleItem,
      nivel: nivelItem,
      mensaje: `No hay BOM cargado para "${tipoMuebleItem}" nivel ${nivelItem}.`,
    });
    itemsIncompletos.push({
      item_id: item.item_id,
      tipo_mueble: tipoMuebleItem,
      nivel: nivelItem,
      color: colorItem,
      razon: 'sin_bom',
      mensaje: 'Item sin BOM definido — no se puede producir.',
    });
    continue;
  }

  const materialesBom = new Map();
  for (const b of bomItem) {
    const matName = String(b.material || '').trim();
    if (!matName) continue;
    if (!materialesBom.has(matName)) {
      materialesBom.set(matName, {
        material: matName,
        parsed: parsearMaterialBom(matName),
        unidad: String(b.unidad || '').trim(),
        cantidad: 0,
        notas: String(b.notas || '').trim(),
      });
    }
    materialesBom.get(matName).cantidad += parseMoney(b.cantidad);
  }

  const materialesItem = [];
  let tienePlacaAsignada = false;

  for (const mat of materialesBom.values()) {
    const parsed = mat.parsed;

    if (!parsed || !parsed.producto) {
      erroresItems.push({
        item_id: item.item_id,
        tipo: 'material_invalido',
        material: mat.material,
        producto_buscado: null,
        mensaje: `No se pudo parsear "${mat.material}".`,
      });
      continue;
    }

    const prodNorm = normText(parsed.producto);
    let candidatos = catalogoStock.filter((c) => normText(c.producto) === prodNorm);

    if (candidatos.length === 0) {
      erroresItems.push({
        item_id: item.item_id,
        tipo: 'sin_sku_en_producto',
        material: mat.material,
        producto_buscado: parsed.producto,
        mensaje: `No hay códigos en stock con Producto "${parsed.producto}".`,
      });
      continue;
    }

    let elegido = null;

    if (parsed.placeholder) {
      let candFiltrados = candidatos;
      if (parsed.filtroExtra) {
        const filtroNorm = normText(parsed.filtroExtra);
        candFiltrados = candidatos.filter((c) =>
          normText(`${c.categoria} ${c.color_variante}`).includes(filtroNorm),
        );
        if (candFiltrados.length === 0) candFiltrados = candidatos;
      }
      elegido = elegirPorColor(candFiltrados, colorNormItem);
      if (!elegido) {
        erroresItems.push({
          item_id: item.item_id,
          tipo: 'sin_color',
          material: mat.material,
          producto_buscado: parsed.producto,
          color: colorItem,
          mensaje: `No hay código de "${parsed.producto}" en color "${colorItem}".`,
        });
        continue;
      }
    } else {
      const catNorm = normText(parsed.categoria);
      const exactos = candidatos.filter((c) => normText(c.categoria) === catNorm);
      if (exactos.length === 0) {
        erroresItems.push({
          item_id: item.item_id,
          tipo: 'sin_sku_producto_categoria',
          material: mat.material,
          producto_buscado: parsed.producto,
          categoria_buscada: parsed.categoria,
          mensaje: `No hay código con Producto="${parsed.producto}" + Categoría="${parsed.categoria}".`,
        });
        continue;
      }
      elegido = exactos.reduce((a, b) => (b.stock > a.stock ? b : a));
    }

    materialesItem.push({
      material: mat.material,
      producto_buscado: parsed.producto,
      categoria_buscada: parsed.categoria,
      placeholder: parsed.placeholder,
      codigo: elegido.codigo,
      producto_stock: elegido.producto,
      categoria_stock: elegido.categoria,
      color_variante_stock: elegido.color_variante,
      medida_stock: elegido.medida,
      unidad: mat.unidad,
      cantidad_requerida: mat.cantidad,
    });

    if (PRODUCTOS_PLACA.has(parsed.producto)) tienePlacaAsignada = true;

    addConsumo(elegido, mat.material, parsed.producto, parsed.categoria,
      mat.unidad, mat.cantidad, item.item_id, colorItem);
  }

  const bomPidePlaca = [...materialesBom.values()].some(
    (m) => m.parsed && PRODUCTOS_PLACA.has(m.parsed.producto),
  );

  if (bomPidePlaca && !tienePlacaAsignada) {
    itemsIncompletos.push({
      item_id: item.item_id,
      tipo_mueble: tipoMuebleItem,
      nivel: nivelItem,
      color: colorItem,
      razon: 'sin_placa_asignada',
      mensaje: 'El BOM pide placa pero no se pudo asignar ninguna.',
    });
  }

  itemsResueltos.push({
    item_id: item.item_id,
    linea: item.linea,
    tipo_mueble: tipoMuebleItem,
    nivel: nivelItem,
    color: colorItem,
    alto_cm: item.alto_cm,
    ancho_cm: item.ancho_cm,
    profundidad_cm: item.profundidad_cm,
    materiales: materialesItem,
    tiene_placa: tienePlacaAsignada,
    completo: tienePlacaAsignada || !bomPidePlaca,
  });
}

// ═══════════════════════════════════════════════════════════════════════════
// 5. Asignación parcial
// ═══════════════════════════════════════════════════════════════════════════

const asignaciones = [];
for (const c of consumoPorCodigo.values()) {
  const unidadDiscreta = /^(placa|unidad|par|kit|servicio)$/i.test(c.unidad_bom);
  const requerido = unidadDiscreta ? Math.ceil(c.requerido) : Number(c.requerido.toFixed(2));
  const disponible = Math.max(0, c.stock_actual);
  const asignado = Math.min(requerido, disponible);
  const faltante = Number((requerido - asignado).toFixed(2));
  const stock_nuevo = Number((c.stock_actual - asignado).toFixed(2));

  asignaciones.push({
    codigo: c.codigo,
    material_bom: c.material_bom,
    producto: c.producto,
    categoria_stock: c.categoria_stock,
    color_variante: c.color_variante,
    medida: c.medida,
    marca: c.marca,
    unidad: c.unidad_bom,
    precio_unit: c.precio_unit,
    row_number: c.row_number,
    requerido,
    disponible: c.stock_actual,
    asignado,
    faltante,
    stock_nuevo,
    valor_stock_nuevo: Number((stock_nuevo * c.precio_unit).toFixed(2)),
    costo_faltante: Number((faltante * c.precio_unit).toFixed(2)),
    items_asociados: c.items_asociados,
    color_solicitado: c.color_solicitado,
  });
}
asignaciones.sort((a, b) => a.codigo.localeCompare(b.codigo));

// ═══════════════════════════════════════════════════════════════════════════
// 6. Resumen y flags — estado_final jerárquico
// ═══════════════════════════════════════════════════════════════════════════

const hayFaltantes = asignaciones.some((a) => a.faltante > 0);
const hayErrores = erroresItems.length > 0;
const hayIncompletos = itemsIncompletos.length > 0;
const hayViolaciones = violaciones.length > 0;
const hayDescontable = asignaciones.some((a) => a.asignado > 0);

const costoTotalFaltantes = Number(asignaciones.reduce((s, a) => s + a.costo_faltante, 0).toFixed(2));
const costoTotalConsumo = Number(asignaciones.reduce((s, a) => s + a.asignado * a.precio_unit, 0).toFixed(2));

// Jerarquía: VIOLACION_INVARIANTE > INCOMPLETO > PENDIENTE_MATERIAL > original
let estadoFinal;
if (hayViolaciones) {
  estadoFinal = 'VIOLACION_INVARIANTE';
} else if (hayIncompletos) {
  estadoFinal = 'INCOMPLETO';
} else if (hayFaltantes || hayErrores) {
  estadoFinal = 'PENDIENTE_MATERIAL';
} else {
  estadoFinal = header.estado;
}

return [
  {
    json: {
      pedido_id: header.pedido_id,
      cliente_id: header.cliente_id,
      cliente_nombre: header.cliente_nombre,
      fecha_entrega: header.fecha_entrega,
      sena: header.sena,
      total: header.total,
