// MAPEO CARGA VENTAS — v7.1 (sin INV-M10)
// ───────────────────────────────────────────────────────────────────────────
// Cambios v7.1 respecto a v7:
//   - Removido INV-M10 (chequeo costo > 5× total). Daba falsos positivos
//     porque algunos precios del stock son por empaque (caja de 500
//     tornillos = $14.504) y no por unidad consumida. El ratio
//     costo/total no es un proxy válido para "precio mal cargado" hasta
//     que se resuelva el tema precio unitario vs precio por empaque.
//   - Quedan 9 invariantes activos (M01..M09).
// ═══════════════════════════════════════════════════════════════════════════

const input = $input.first().json;

// ── Config ────────────────────────────────────────────────────────────────
const PRODUCTOS_IGNORABLES = new Set([
  'Tornillo 50mm',
  'Tornillo 30mm',
  'Tornillo 16mm',
  'Clavo',
]);

// ── Datos base ────────────────────────────────────────────────────────────
const fechaISO = input.fecha_procesado || new Date().toISOString();
const fechaCorta = fechaISO.replace('T', ' ').substring(0, 16);
const pedidoId = input.pedido_id;
const cliente = input.cliente_nombre;

// ── Arrays del resolver ───────────────────────────────────────────────────
const erroresItems = input.errores_items || [];
const asignaciones = input.asignaciones || [];
const itemsIncompletos = input.items_incompletos || [];
const itemsResueltos = input.items_resueltos || [];
const violacionesResolver = input.violaciones || [];

// ═══════════════════════════════════════════════════════════════════════════
// 1. CHEQUEO DE INVARIANTES (sobre output del resolver)
// ═══════════════════════════════════════════════════════════════════════════

const violacionesMapeo = [];

const addViolacion = (id, tipo, mensaje, datos = {}) => {
  violacionesMapeo.push({
    invariante_id: id,
    tipo,
    mensaje,
    datos,
    origen: 'mapeo_carga_ventas',
  });
};

// INV-M01: pedido_id y cliente_nombre no vacíos
if (!pedidoId) {
  addViolacion('INV-M01', 'pedido_id_vacio',
    'El output del resolver no tiene pedido_id.',
    { input_keys: Object.keys(input) });
}
if (!cliente) {
  addViolacion('INV-M01', 'cliente_vacio',
    'El output del resolver no tiene cliente_nombre.',
    { pedido_id: pedidoId });
}

// INV-M02: Todo item resuelto tiene al menos 1 material (salvo que esté listado como incompleto)
for (const item of itemsResueltos) {
  if (!item.materiales || item.materiales.length === 0) {
    const yaIncompleto = itemsIncompletos.some((i) => i.item_id === item.item_id);
    if (!yaIncompleto) {
      addViolacion('INV-M02', 'item_sin_materiales',
        `Item ${item.item_id} aparece en items_resueltos pero no tiene materiales ni está en items_incompletos.`,
        { item_id: item.item_id, tipo_mueble: item.tipo_mueble, nivel: item.nivel });
    }
  }
}

// INV-M03: stock_nuevo >= 0 en toda asignación
for (const a of asignaciones) {
  if (a.stock_nuevo < 0) {
    addViolacion('INV-M03', 'stock_nuevo_negativo',
      `Código ${a.codigo} tendría stock_nuevo=${a.stock_nuevo} tras descuento.`,
      { codigo: a.codigo, stock_actual: a.disponible, asignado: a.asignado, stock_nuevo: a.stock_nuevo });
  }
}

// INV-M04: asignado + faltante == requerido (aritmética)
for (const a of asignaciones) {
  const suma = Number((a.asignado + a.faltante).toFixed(2));
  if (Math.abs(suma - a.requerido) > 0.01) {
    addViolacion('INV-M04', 'aritmetica_rota',
      `Código ${a.codigo}: asignado(${a.asignado}) + faltante(${a.faltante}) ≠ requerido(${a.requerido}).`,
      { codigo: a.codigo, asignado: a.asignado, faltante: a.faltante, requerido: a.requerido });
  }
}

// INV-M05: Si estado_final='Confirmado' → sin faltantes ni incompletos
if (input.estado_final === 'Confirmado') {
  const conFaltante = asignaciones.filter((a) => a.faltante > 0);
  if (conFaltante.length > 0) {
    addViolacion('INV-M05', 'confirmado_con_faltantes',
      `Resolver marcó Confirmado pero hay ${conFaltante.length} códigos con faltante.`,
      { codigos: conFaltante.map((a) => a.codigo) });
  }
  if (itemsIncompletos.length > 0) {
    addViolacion('INV-M05', 'confirmado_con_incompletos',
      `Resolver marcó Confirmado pero hay ${itemsIncompletos.length} items incompletos.`,
      { items: itemsIncompletos.map((i) => i.item_id) });
  }
}

// INV-M06: Toda asignación tiene código no vacío
for (const a of asignaciones) {
  if (!a.codigo || String(a.codigo).trim() === '') {
    addViolacion('INV-M06', 'asignacion_sin_codigo',
      'Hay una asignación con código vacío.',
      { material: a.material_bom, producto: a.producto });
  }
}

// INV-M07: Ningún item_id aparece simultáneamente en items_incompletos y en una asignación con asignado > 0
const idsIncompletos = new Set(itemsIncompletos.map((i) => i.item_id));
for (const a of asignaciones) {
  if (a.asignado > 0) {
    for (const itemId of (a.items_asociados || [])) {
      if (idsIncompletos.has(itemId)) {
        addViolacion('INV-M07', 'incompleto_con_descuento',
          `Item ${itemId} está marcado incompleto pero hay descuento (${a.asignado}) en código ${a.codigo}.`,
          { item_id: itemId, codigo: a.codigo, asignado: a.asignado });
      }
    }
  }
}

// INV-M08: Fecha procesado válida y no futura
const fechaProc = new Date(fechaISO);
const ahora = new Date();
const margen = 60 * 60 * 1000; // 1 hora de tolerancia por timezone
if (!Number.isFinite(fechaProc.getTime())) {
  addViolacion('INV-M08', 'fecha_invalida',
    `fecha_procesado no es parseable: "${fechaISO}".`,
    { fecha_recibida: fechaISO });
} else if (fechaProc.getTime() > ahora.getTime() + margen) {
  addViolacion('INV-M08', 'fecha_futura',
    `fecha_procesado está en el futuro: "${fechaISO}".`,
    { fecha_recibida: fechaISO, ahora: ahora.toISOString() });
}

// INV-M09: No hay códigos duplicados en asignaciones
const contadorAsignaciones = new Map();
for (const a of asignaciones) {
  contadorAsignaciones.set(a.codigo, (contadorAsignaciones.get(a.codigo) || 0) + 1);
}
for (const [codigo, count] of contadorAsignaciones) {
  if (count > 1) {
    addViolacion('INV-M09', 'asignacion_duplicada',
      `El código "${codigo}" aparece ${count} veces en asignaciones.`,
      { codigo, ocurrencias: count });
  }
}

