const todasViolaciones = [...violacionesResolver, ...violacionesMapeo];
const hayViolaciones = todasViolaciones.length > 0;

const esErrorBloqueante = (e) =>
  !PRODUCTOS_IGNORABLES.has(e.producto_buscado || e.categoria_stock || '');

const erroresBloqueantes = erroresItems.filter(esErrorBloqueante);
const asignacionesConFaltante = asignaciones.filter((a) => a.faltante > 0);

const hayBloqueante =
  hayViolaciones ||
  erroresBloqueantes.length > 0 ||
  asignacionesConFaltante.length > 0 ||
  itemsIncompletos.length > 0;

const procesar = !hayBloqueante;

let estadoFinalPedido;
if (hayViolaciones) {
  estadoFinalPedido = 'VIOLACION_INVARIANTE';
} else if (itemsIncompletos.length > 0) {
  estadoFinalPedido = 'INCOMPLETO';
} else if (procesar) {
