      },
    });
  }
}

// ── 3c. Faltantes de stock ────────────────────────────────────────────────
for (const a of asignacionesConFaltante) {
  output.push({
    json: {
      destino: 'faltante_stock',
      pedido_id: pedidoId,
      data: {
