        MATERIAL: e.material || '',
        PRODUCTO_BUSCADO: e.producto_buscado || '',
        CATEGORIA_BUSCADA: e.categoria_buscada || e.categoria_stock || '',
        TIPO_ERROR: e.tipo || '',
        MENSAJE: e.mensaje || '',
