const inRange = (n, min, max) => isFinite(n) && n >= min && n <= max;
const isClienteIdValido = (s) => typeof s === 'string' && /^CLI-\d{3,}$/.test(s);
const isFechaISO = (s) => typeof s === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(s) && !isNaN(new Date(s).getTime());
const limpiar = (s) => (typeof s === 'string' ? s.trim() : '');

// === INPUT ===
const payload = $input.first().json || {};
const body = payload.body || {};
const data = body.data || {};
const errores = [];

// === PIN / ACTION ===
if (String(body.pin || '') !== PIN_ESPERADO) errores.push('PIN inválido');
if (body.action !== 'registrar_pedido') {
  errores.push(`action inválida "${body.action}" (esperado "registrar_pedido")`);
}

// === CLIENTE ===
if (!isClienteIdValido(data.cliente_id)) {
  errores.push(`cliente_id inválido "${data.cliente_id}"`);
}

// === FECHA ENTREGA ===
if (!isFechaISO(data.fecha_entrega)) {
  errores.push(`fecha_entrega inválida "${data.fecha_entrega}" (YYYY-MM-DD)`);
} else {
  const hoy = new Date(); hoy.setHours(0, 0, 0, 0);
  if (new Date(data.fecha_entrega) < hoy) {
    errores.push(`fecha_entrega en el pasado "${data.fecha_entrega}"`);
  }
}

// === MONTOS ===
const total = parseNum(data.total);
if (!inRange(total, MIN_MONTO, MAX_MONTO)) {
  errores.push(`"${data.total}" (total debe ser número > 0 y ≤ ${MAX_MONTO})`);
}
const sena = parseNum(data.sena);
if (!inRange(sena, 0, MAX_MONTO)) {
  errores.push(`"${data.sena}" (seña debe ser número ≥ 0 y ≤ ${MAX_MONTO})`);
}
if (isFinite(total) && isFinite(sena) && sena > total) {
  errores.push(`la seña (${sena}) no puede superar el total (${total})`);
}
const saldo = isFinite(total) && isFinite(sena) ? total - sena : 0;

// === ITEMS ===
const items = Array.isArray(data.items) ? data.items : [];
if (items.length === 0) errores.push('items vacío: el pedido debe tener al menos un mueble');
if (items.length > MAX_ITEMS_POR_PEDIDO) {
  errores.push(`demasiados muebles (${items.length} > ${MAX_ITEMS_POR_PEDIDO})`);
}

const itemsNorm = [];
items.forEach((it, idx) => {
  const prefix = `items[${idx}]`;
  const n = {};

  if (!TIPOS_MUEBLE_VALIDOS.includes(it.tipo_mueble)) {
    errores.push(`${prefix}.tipo_mueble inválido "${it.tipo_mueble}"`);
  } else n.tipo_mueble = it.tipo_mueble;

  const alto = parseNum(it.alto);
  if (!inRange(alto, MIN_DIMENSION_CM, MAX_DIMENSION_CM)) {
    errores.push(`${prefix}.alto "${it.alto}" (entre ${MIN_DIMENSION_CM} y ${MAX_DIMENSION_CM} cm)`);
  } else n.alto_cm = alto;

  const ancho = parseNum(it.ancho);
  if (!inRange(ancho, MIN_DIMENSION_CM, MAX_DIMENSION_CM)) {
    errores.push(`${prefix}.ancho "${it.ancho}" (entre ${MIN_DIMENSION_CM} y ${MAX_DIMENSION_CM} cm)`);
  } else n.ancho_cm = ancho;

  const prof = parseNum(it.profundidad);
  if (!inRange(prof, MIN_DIMENSION_CM, MAX_DIMENSION_CM)) {
    errores.push(`${prefix}.profundidad "${it.profundidad}" (entre ${MIN_DIMENSION_CM} y ${MAX_DIMENSION_CM} cm)`);
  } else n.profundidad_cm = prof;

  const color = limpiar(it.color);
  if (!color) errores.push(`${prefix}.color vacío`);
  else n.color = color;

  const nivel = String(it.nivel ?? '').trim();
  if (!NIVELES_VALIDOS.includes(nivel)) {
    errores.push(`${prefix}.nivel "${it.nivel}" (2–5)`);
  } else n.categoria = nivel;

  itemsNorm.push(n);
});

// === CORTE POR ERRORES ===
if (errores.length > 0) {
  throw new Error('[normalizar_pedido] ' + errores.join(' | '));
}

// === IDS Y METADATA ===
const ahora = new Date();
const yy = String(ahora.getFullYear()).slice(-2);
const mm = String(ahora.getMonth() + 1).padStart(2, '0');
const dd = String(ahora.getDate()).padStart(2, '0');
const hh = String(ahora.getHours()).padStart(2, '0');
const mi = String(ahora.getMinutes()).padStart(2, '0');
const ss = String(ahora.getSeconds()).padStart(2, '0');
const pedidoId = `PED-${yy}${mm}${dd}-${hh}${mi}${ss}`;
const fechaAlta = `${ahora.getFullYear()}-${mm}-${dd}`;
const notas = limpiar(data.notas);

// === SALIDA: 1 item "pedido" + N items "item" ===
const salida = [];

salida.push({
  json: {
    tipo: 'pedido',
    pedido_id: pedidoId,
    cliente_id: data.cliente_id,
    cliente_nombre: limpiar(data.cliente_nombre),
    fecha_entrega: data.fecha_entrega,
    sena: sena,
    total: total,
    saldo: saldo,
    estado: ESTADO_INICIAL,
    notas: notas,
    cantidad_muebles: itemsNorm.length,
    fecha_alta: fechaAlta,
  },
});

itemsNorm.forEach((m, i) => {
  salida.push({
    json: {
      tipo: 'item',
      item_id: `${pedidoId}-${String(i + 1).padStart(2, '0')}`,
      pedido_id: pedidoId,
      linea: i + 1,
      tipo_mueble: m.tipo_mueble,
      alto_cm: m.alto_cm,
      ancho_cm: m.ancho_cm,
      profundidad_cm: m.profundidad_cm,
      color: m.color,
      categoria: m.categoria,
      estado_item: ESTADO_INICIAL,
    },
  });
});

return salida;

// Calcular nuevos valores para update en Sheets
const catalogo = $('Filter1').all();
const compras  = $input.all(); // viene del Switch rama EXISTE

const norm = (v) => String(v ?? '').trim().toUpperCase();
const toNum = (v) => {
  const n = Number(String(v ?? '0').replace(',', '.'));
  return Number.isFinite(n) ? n : 0;
};

// Indexar catálogo por código
const byCodigo = new Map();
for (const item of catalogo) {
  byCodigo.set(norm(item.json['Código']), item.json);
}

return compras.map(item => {
  const d = item.json;
  const row = byCodigo.get(norm(d.codigo)) ?? {};

  const stockActual = toNum(row['Stock Actual']);
  const precioUnit  = toNum(row['Precio Unit.']);

  const cantidadNueva = toNum(d.cantidad);
  const precioNuevo   = toNum(d.precio);

  const nuevoStock = stockActual + cantidadNueva;
  // Valor total = stock × precio unitario (el que corresponda)
  const nuevoValor = nuevoStock * (precioNuevo || precioUnit);

  return {
    json: {
      ...d,
      stock_anterior: stockActual,
      nuevo_stock: nuevoStock,
      nuevo_valor: nuevoValor,
      proveedor: d.proveedor,
    },
  };
});
